const { ethers } = require('ethers');
require('dotenv').config();

class EthereumService {
  constructor() {
    // Connect to Ethereum network
    this.provider = new ethers.JsonRpcProvider(
      process.env.RPC_URL || 'https://mainnet.infura.io/v3/YOUR-PROJECT-ID'
    );
    
    // Initialize wallet from environment variable (secure)
    this.wallet = null;
    this.initializeWallet();
  }

  initializeWallet() {
    // Secure: Load private key from environment variable
    const privateKey = process.env.PRIVATE_KEY;
    
    if (!privateKey) {
      throw new Error('PRIVATE_KEY not found in environment variables');
    }

    // Validate private key format
    if (!privateKey.match(/^0x[0-9a-fA-F]{64}$/)) {
      throw new Error('Invalid private key format');
    }

    this.wallet = new ethers.Wallet(privateKey, this.provider);
  }

  // Alternative: Use encrypted keystore
  async initializeFromKeystore(keystorePath, password) {
    const fs = require('fs');
    const keystoreJson = fs.readFileSync(keystorePath, 'utf8');
    this.wallet = await ethers.Wallet.fromEncryptedJson(keystoreJson, password);
    this.wallet = this.wallet.connect(this.provider);
  }

  // Alternative: Use mnemonic from environment
  initializeFromMnemonic() {
    const mnemonic = process.env.MNEMONIC;
    
    if (!mnemonic) {
      throw new Error('MNEMONIC not found in environment variables');
    }

    this.wallet = ethers.Wallet.fromPhrase(mnemonic);
    this.wallet = this.wallet.connect(this.provider);
  }

  async getBalance(address) {
    const balance = await this.provider.getBalance(address || this.wallet.address);
    return ethers.formatEther(balance);
  }

  async sendETH(toAddress, amountInEther) {
    try {
      // Validate inputs
      if (!ethers.isAddress(toAddress)) {
        throw new Error('Invalid recipient address');
      }

      const tx = {
        to: toAddress,
        value: ethers.parseEther(amountInEther.toString()),
      };

      // Estimate gas
      const gasEstimate = await this.wallet.estimateGas(tx);
      tx.gasLimit = gasEstimate;

      // Get current gas price
      const feeData = await this.provider.getFeeData();
      tx.maxFeePerGas = feeData.maxFeePerGas;
      tx.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;

      // Send transaction
      const txResponse = await this.wallet.sendTransaction(tx);
      console.log(`Transaction sent: ${txResponse.hash}`);

      // Wait for confirmation
      const receipt = await txResponse.wait();
      console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

      return {
        hash: txResponse.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
      };
    } catch (error) {
      console.error('Error sending ETH:', error.message);
      throw error;
    }
  }

  async interactWithContract(contractAddress, abi, functionName, params = [], value = '0') {
    try {
      // Validate contract address
      if (!ethers.isAddress(contractAddress)) {
        throw new Error('Invalid contract address');
      }

      // Create contract instance
      const contract = new ethers.Contract(contractAddress, abi, this.wallet);

      // Prepare transaction options
      const txOptions = {};
      
      if (value !== '0') {
        txOptions.value = ethers.parseEther(value.toString());
      }

      // Call contract function
      const tx = await contract[functionName](...params, txOptions);
      console.log(`Contract interaction sent: ${tx.hash}`);

      // Wait for confirmation
      const receipt = await tx.wait();
      console.log(`Transaction confirmed in block ${receipt.blockNumber}`);

      return {
        hash: tx.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
      };
    } catch (error) {
      console.error('Error interacting with contract:', error.message);
      throw error;
    }
  }

  async readContract(contractAddress, abi, functionName, params = []) {
    try {
      if (!ethers.isAddress(contractAddress)) {
        throw new Error('Invalid contract address');
      }

      const contract = new ethers.Contract(contractAddress, abi, this.provider);
      const result = await contract[functionName](...params);
      
      return result;
    } catch (error) {
      console.error('Error reading contract:', error.message);
      throw error;
    }
  }

  async signMessage(message) {
    const signature = await this.wallet.signMessage(message);
    return signature;
  }

  async signTypedData(domain, types, value) {
    const signature = await this.wallet.signTypedData(domain, types, value);
    return signature;
  }

  getAddress() {
    return this.wallet.address;
  }

  async getNonce() {
    return await this.wallet.getNonce();
  }

  async estimateGas(tx) {
    return await this.wallet.estimateGas(tx);
  }
}

